//#region src/main/services/backup.js
function copyDirRecursive(src, dest) {
	if (!fs.default.existsSync(src)) return;
	fs.default.mkdirSync(dest, { recursive: true });
	for (const entry of fs.default.readdirSync(src, { withFileTypes: true })) {
		const s = path.default.join(src, entry.name);
		const d = path.default.join(dest, entry.name);
		if (entry.isDirectory()) copyDirRecursive(s, d);
		else fs.default.copyFileSync(s, d);
	}
}
function countFiles(dir) {
	if (!fs.default.existsSync(dir)) return 0;
	let n = 0;
	for (const e of fs.default.readdirSync(dir, { withFileTypes: true })) n += e.isDirectory() ? countFiles(path.default.join(dir, e.name)) : 1;
	return n;
}
function runPowerShell(cmd) {
	return new Promise((resolve, reject) => {
		(0, child_process.execFile)("powershell.exe", [
			"-NoProfile",
			"-Command",
			cmd
		], { maxBuffer: 10 * 1024 * 1024 }, (err, stdout, stderr) => {
			if (err) reject(new Error(stderr || err.message));
			else resolve(stdout);
		});
	});
}
async function eseguiBackup() {
	const { filePath } = await electron.dialog.showSaveDialog({
		title: "Salva backup",
		defaultPath: `ImmobiliBackup_${(/* @__PURE__ */ new Date()).toISOString().split("T")[0]}.backup`,
		filters: [{
			name: "Backup Immobili",
			extensions: ["backup"]
		}]
	});
	if (!filePath) return null;
	const userDataPath = electron.app.getPath("userData");
	const dbPath = path.default.join(userDataPath, "immobili.db");
	const docsPath = path.default.join(userDataPath, "documenti");
	const fotosPath = path.default.join(userDataPath, "foto");
	const tempDir = path.default.join(userDataPath, "_backup_tmp");
	if (fs.default.existsSync(tempDir)) fs.default.rmSync(tempDir, { recursive: true });
	fs.default.mkdirSync(tempDir, { recursive: true });
	try {
		getDb().exec("PRAGMA wal_checkpoint(TRUNCATE)");
	} catch {}
	fs.default.copyFileSync(dbPath, path.default.join(tempDir, "immobili.db"));
	copyDirRecursive(docsPath, path.default.join(tempDir, "documenti"));
	copyDirRecursive(fotosPath, path.default.join(tempDir, "foto"));
	const manifest = {
		version: electron.app.getVersion(),
		creato_il: (/* @__PURE__ */ new Date()).toISOString(),
		num_documenti: countFiles(docsPath),
		num_foto: countFiles(fotosPath)
	};
	fs.default.writeFileSync(path.default.join(tempDir, "manifest.json"), JSON.stringify(manifest, null, 2));
	const zipPath = filePath.replace(/\.backup$/, "") + "_tmp.zip";
	await runPowerShell(`Compress-Archive -Path "${tempDir}\\*" -DestinationPath "${zipPath}" -Force`);
	if (fs.default.existsSync(filePath)) fs.default.unlinkSync(filePath);
	fs.default.renameSync(zipPath, filePath);
	fs.default.rmSync(tempDir, { recursive: true });
	return {
		filePath,
		manifest
	};
}
async function eseguiRestore() {
	const { filePaths, canceled } = await electron.dialog.showOpenDialog({
		title: "Seleziona file di backup",
		filters: [{
			name: "Backup Immobili",
			extensions: ["backup"]
		}],
		properties: ["openFile"]
	});
	if (canceled || !filePaths?.length) return null;
	const backupFile = filePaths[0];
	const userDataPath = electron.app.getPath("userData");
	const tempDir = path.default.join(userDataPath, "_restore_tmp");
	if (fs.default.existsSync(tempDir)) fs.default.rmSync(tempDir, { recursive: true });
	fs.default.mkdirSync(tempDir, { recursive: true });
	await runPowerShell(`Expand-Archive -Path "${backupFile}" -DestinationPath "${tempDir}" -Force`);
	const manifestPath = path.default.join(tempDir, "manifest.json");
	if (!fs.default.existsSync(manifestPath)) {
		fs.default.rmSync(tempDir, { recursive: true });
		throw new Error("File di backup non valido Рђћ manifest mancante");
	}
	const manifest = JSON.parse(fs.default.readFileSync(manifestPath, "utf-8"));
	const dbPath = path.default.join(userDataPath, "immobili.db");
	if (fs.default.existsSync(dbPath)) fs.default.copyFileSync(dbPath, dbPath + ".pre-restore");
	const newDb = path.default.join(tempDir, "immobili.db");
	if (fs.default.existsSync(newDb)) fs.default.copyFileSync(newDb, dbPath);
	const docsPath = path.default.join(userDataPath, "documenti");
	const newDocs = path.default.join(tempDir, "documenti");
	if (fs.default.existsSync(newDocs)) {
		if (fs.default.existsSync(docsPath)) fs.default.rmSync(docsPath, { recursive: true });
		copyDirRecursive(newDocs, docsPath);
	}
	const fotosPath = path.default.join(userDataPath, "foto");
	const newFotos = path.default.join(tempDir, "foto");
	if (fs.default.existsSync(newFotos)) {
		if (fs.default.existsSync(fotosPath)) fs.default.rmSync(fotosPath, { recursive: true });
		copyDirRecursive(newFotos, fotosPath);
	}
	fs.default.rmSync(tempDir, { recursive: true });
	return {
		manifest,
		richiedeRiavvio: true
	};
}
