//#region src/main/index.js
var mainWindow;
var tray;
function createWindow() {
	mainWindow = new electron.BrowserWindow({
		width: 1400,
		height: 900,
		minWidth: 1100,
		minHeight: 700,
		title: "Immobili Manager",
		backgroundColor: "#f8fafc",
		webPreferences: {
			preload: path.default.join(__dirname, "../preload/index.js"),
			contextIsolation: true,
			nodeIntegration: false
		},
		show: false
	});
	if (process.env.ELECTRON_RENDERER_URL) mainWindow.loadURL(process.env.ELECTRON_RENDERER_URL);
	else mainWindow.loadFile(path.default.join(__dirname, "../renderer/index.html"));
	mainWindow.once("ready-to-show", () => mainWindow.show());
	mainWindow.on("close", (e) => {
		if (!electron.app.isQuitting) {
			e.preventDefault();
			mainWindow.hide();
		}
	});
}
function createTray() {
	const iconPath = path.default.join(__dirname, "../../resources/tray-icon.png");
	const icon = electron.nativeImage.createFromPath(iconPath);
	tray = new electron.Tray(icon.isEmpty() ? electron.nativeImage.createEmpty() : icon);
	const menu = electron.Menu.buildFromTemplate([
		{
			label: "Apri Immobili Manager",
			click: () => {
				mainWindow.show();
				mainWindow.focus();
			}
		},
		{ type: "separator" },
		{
			label: "Esci",
			click: () => {
				electron.app.isQuitting = true;
				electron.app.quit();
			}
		}
	]);
	tray.setToolTip("Immobili Manager");
	tray.setContextMenu(menu);
	tray.on("double-click", () => {
		mainWindow.show();
		mainWindow.focus();
	});
}
electron.app.whenReady().then(() => {
	const { docsPath, fotosPath } = initDb();
	registraHandlers(docsPath, fotosPath);
	createWindow();
	createTray();
	avviaScheduler();
	electron.app.on("activate", () => {
		if (electron.BrowserWindow.getAllWindows().length === 0) createWindow();
	});
});
electron.app.on("before-quit", () => {
	electron.app.isQuitting = true;
	fermaScheduler();
});
electron.app.on("window-all-closed", () => {
	if (process.platform !== "darwin") {}
});
